import React, { useState, useEffect } from "react";
import { PRIORITY_META, STATUS_META } from "../utils/costants";

// Smooth animations
const smoothStyles = `
  @keyframes fadeIn {
    from {
      opacity: 0;
    }
    to {
      opacity: 1;
    }
  }
  
  @keyframes slideUp {
    from {
      opacity: 0;
      transform: translateY(20px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }
  
  @keyframes scaleIn {
    from {
      opacity: 0;
      transform: scale(0.95);
    }
    to {
      opacity: 1;
      transform: scale(1);
    }
  }
  
  * {
    scroll-behavior: smooth;
  }
`;

// Inject styles
if (typeof document !== 'undefined' && !document.getElementById('featureModal-styles')) {
  const style = document.createElement('style');
  style.id = 'featureModal-styles';
  style.innerHTML = smoothStyles;
  document.head.appendChild(style);
}

export default function FeatureModal({ feature, onClose }) {
  const [expandedImage, setExpandedImage] = useState(false);

  useEffect(() => {
    const handler = (e) => {
      if (e.key === "Escape") {
        if (expandedImage) setExpandedImage(false);
        else onClose();
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [onClose, expandedImage]);

  if (!feature) return null;

  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];

  // Expanded image view
  if (expandedImage) {
    return (
      <div
        style={{
          position: "fixed",
          inset: 0,
          zIndex: 2000,
          background: "rgba(0, 0, 0, 0.9)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          padding: "16px",
          backdropFilter: "blur(4px)",
        }}
        onClick={() => setExpandedImage(false)}
      >
        <div
          style={{
            position: "relative",
            width: "100%",
            height: "100%",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          {/* Image - True Fullscreen */}
          {feature.image && (
            <img
              src={`http://localhost:5000/api/features/images/${feature.image}`}
              alt={feature.title}
              style={{
                maxWidth: "98vw",
                maxHeight: "90vh",
                width: "auto",
                height: "auto",
                borderRadius: "0px",
                objectFit: "contain",
                boxShadow: "none",
              }}
            />
          )}

          {/* Close button - Top Right Corner */}
          <button
            onClick={() => setExpandedImage(false)}
            style={{
              position: "absolute",
              top: "24px",
              right: "24px",
              width: "44px",
              height: "44px",
              borderRadius: "50%",
              background: "rgba(0, 0, 0, 0.6)",
              border: "none",
              color: "white",
              fontSize: "24px",
              fontWeight: 600,
              cursor: "pointer",
              transition: "all 0.2s",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
            onMouseOver={(e) => {
              e.target.style.background = "rgba(0, 0, 0, 0.8)";
            }}
            onMouseOut={(e) => {
              e.target.style.background = "rgba(0, 0, 0, 0.6)";
            }}
          >
            ✕
            Close (Press ESC)
          </button>
        </div>
      </div>
    );
  }

  // Regular modal view - FULLSCREEN
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 1000,
        background: "white",
        display: "flex",
        flexDirection: "column",
        overflow: "auto",
      }}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div
        style={{
          background: "white",
          width: "100%",
          height: "100%",
          overflow: "auto",
        }}
      >
        {/* Header with gradient background - FULLSCREEN */}
        <div
          style={{
            background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
            padding: "40px 50px",
            color: "white",
            position: "sticky",
            top: 0,
            zIndex: 10,
            boxShadow: "0 4px 20px rgba(0, 0, 0, 0.1)",
          }}
        >
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
            <div style={{ flex: 1 }}>
              <h1 style={{ margin: "0 0 16px 0", fontSize: "36px", fontWeight: 700 }}>
                {feature.title}
              </h1>
              <div style={{ display: "flex", gap: "12px", alignItems: "center" }}>
                <span
                  style={{
                    display: "inline-block",
                    padding: "8px 14px",
                    background: "rgba(255, 255, 255, 0.2)",
                    borderRadius: "20px",
                    fontSize: "13px",
                    fontWeight: 600,
                    color: "white",
                  }}
                >
                  {sm?.icon} {feature.status}
                </span>
                <span
                  style={{
                    display: "inline-block",
                    padding: "8px 14px",
                    background: pm?.color || "rgba(255, 255, 255, 0.2)",
                    borderRadius: "20px",
                    fontSize: "13px",
                    fontWeight: 600,
                    color: "white",
                  }}
                >
                  {feature.priority} Priority
                </span>
              </div>
            </div>
            <button
              onClick={onClose}
              style={{
                background: "rgba(255, 255, 255, 0.2)",
                border: "none",
                fontSize: "28px",
                cursor: "pointer",
                color: "white",
                padding: "10px 14px",
                width: "48px",
                height: "48px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                borderRadius: "8px",
                transition: "background 0.2s",
                flexShrink: 0,
              }}
              onMouseOver={(e) => (e.target.style.background = "rgba(255, 255, 255, 0.3)")}
              onMouseOut={(e) => (e.target.style.background = "rgba(255, 255, 255, 0.2)")}
            >
              ✕
            </button>
          </div>
        </div>

        {/* Body - FULLSCREEN */}
        <div style={{ padding: "50px", maxWidth: "1200px", margin: "0 auto", width: "100%" }}>
          {/* Image at top if available - clickable to expand */}
          {feature.image && (
            <div style={{ marginBottom: "40px" }}>
              <img
                src={`http://localhost:5000/api/features/images/${feature.image}`}
                alt={feature.title}
                onClick={() => setExpandedImage(true)}
                style={{
                  width: "100%",
                  maxHeight: "500px",
                  borderRadius: "12px",
                  border: "1px solid #e5e7eb",
                  objectFit: "cover",
                  cursor: "pointer",
                  transition: "transform 0.2s, box-shadow 0.2s",
                }}
                onMouseOver={(e) => {
                  e.currentTarget.style.transform = "scale(1.02)";
                  e.currentTarget.style.boxShadow = "0 10px 25px rgba(0, 0, 0, 0.15)";
                }}
                onMouseOut={(e) => {
                  e.currentTarget.style.transform = "scale(1)";
                  e.currentTarget.style.boxShadow = "none";
                }}
              />
              <p
                style={{
                  fontSize: "13px",
                  color: "#9ca3af",
                  marginTop: "12px",
                  textAlign: "center",
                }}
              >
                Click image to expand
              </p>
            </div>
          )}

          {/* Description as paragraph */}
          <div style={{ marginBottom: "40px" }}>
            <h3
              style={{
                fontSize: "16px",
                fontWeight: 700,
                color: "#667eea",
                textTransform: "uppercase",
                letterSpacing: "0.5px",
                marginBottom: "16px",
              }}
            >
              Description
            </h3>
            <p
              style={{
                fontSize: "16px",
                color: "#374151",
                lineHeight: "1.8",
                whiteSpace: "pre-wrap",
                margin: 0,
                fontWeight: 400,
              }}
            >
              {feature.description}
            </p>
          </div>

          {/* Details grid */}
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr 1fr",
              gap: "32px",
              padding: "32px",
              background: "#f9fafb",
              borderRadius: "12px",
              marginBottom: "40px",
            }}
          >
            <div>
              <p
                style={{
                  fontSize: "12px",
                  fontWeight: 700,
                  color: "#9ca3af",
                  textTransform: "uppercase",
                  letterSpacing: "0.5px",
                  margin: "0 0 8px 0",
                }}
              >
                Status
              </p>
              <div
                style={{
                  fontSize: "16px",
                  fontWeight: 600,
                  color: sm?.color || "#6b7280",
                  display: "flex",
                  alignItems: "center",
                  gap: "6px",
                }}
              >
                {sm?.icon} {feature.status}
              </div>
            </div>
            <div>
              <p
                style={{
                  fontSize: "12px",
                  fontWeight: 700,
                  color: "#9ca3af",
                  textTransform: "uppercase",
                  letterSpacing: "0.5px",
                  margin: "0 0 8px 0",
                }}
              >
                Priority
              </p>
              <div
                style={{
                  fontSize: "16px",
                  fontWeight: 600,
                  color: pm?.color || "#6b7280",
                }}
              >
                {feature.priority}
              </div>
            </div>
          </div>

          {/* Close Button */}
          <button
            onClick={onClose}
            style={{
              width: "100%",
              padding: "16px",
              background: "#667eea",
              border: "none",
              borderRadius: "0",
              fontSize: "16px",
              fontWeight: 600,
              cursor: "pointer",
              color: "white",
              transition: "background 0.2s",
              marginTop: "40px",
            }}
            onMouseOver={(e) => (e.target.style.background = "#764ba2")}
            onMouseOut={(e) => (e.target.style.background = "#667eea")}
          >
            Close
          </button>
        </div>
      </div>
    </div>
  );
}
